"""ResNet-50 — Generated by Lean 4 → JAX
Architecture: Conv(3→64,7x7/2)+BN → Pool(3x3) → BN3(64→256,s1) → BN4(256→512,s2) → BN6(512→1024,s2) → BN3(1024→2048,s2) → GAP → 2048→10
Parameters: 23528522
Matching: Convolutional Neural Networks with Swift for TensorFlow
"""
import jax
import jax.numpy as jnp
from jax import random, jit, value_and_grad
from jax.sharding import Mesh, NamedSharding, PartitionSpec as P
import numpy as np
import struct, os, time, json

# ═══════════════════════════════════════════════════════════════════════
#  Imagenette data loading. The phase-3 preprocessor stores TRAIN at
#  256×256 (so the Lean trainer's random-crop aug can pull a 224×224
#  window per step) but stores VAL at 224×224 already (no aug at
#  eval). The loader auto-detects by checking the per-record byte
#  count from the file size + count header. Both paths center-crop
#  to 224×224 + ImageNet-normalize.
# ═══════════════════════════════════════════════════════════════════════

def load_imagenette(path):
    DST = 224
    with open(path, "rb") as f:
        count = struct.unpack("<I", f.read(4))[0]
        data = np.frombuffer(f.read(), dtype=np.uint8)
    record_size = len(data) // count
    # Each record is 1-byte label + 3*SRC*SRC image bytes.
    src_pixels = (record_size - 1) // 3
    SRC = int(np.sqrt(src_pixels))
    assert SRC * SRC * 3 + 1 == record_size, (record_size, SRC, path)
    off = (SRC - DST) // 2
    data = data.reshape(count, record_size)
    labels = data[:, 0].astype(np.int32)
    images = data[:, 1:].astype(np.float32) / 255.0
    images = images.reshape(count, 3, SRC, SRC)
    if SRC != DST:
        images = images[:, :, off:off+DST, off:off+DST]
    mean = np.array([0.485, 0.456, 0.406]).reshape(1, 3, 1, 1)
    std = np.array([0.229, 0.224, 0.225]).reshape(1, 3, 1, 1)
    images = ((images - mean) / std).reshape(count, -1)
    return images, labels

# Matmul compute dtype (mixed precision). bf16 casts matmul operands and
# returns fp32; master weights / LayerNorm / softmax stay fp32.
# Helps matmul-bound nets (ViT/transformers ~2.7-3.6x on gfx1100).
DT = jnp.bfloat16
def mm(a, b):
    return (a.astype(DT) @ b.astype(DT)).astype(jnp.float32)

# Conv compute dtype. Independent of DT: convs stay fp32 on MIOpen/gfx1100
# (bf16 conv is slower there), but opt into bf16 on cuDNN/CUDA where tensor
# cores make bf16 conv ~1.6x faster. CONV_DT=float32 -> casts are no-ops.
CONV_DT = jnp.bfloat16
def convdt(x):
    return x.astype(CONV_DT)

# ═══════════════════════════════════════════════════════════════════════
#  Conv / Pool helpers
# ═══════════════════════════════════════════════════════════════════════

def conv2d(x, w, b, padding='SAME', stride=(1,1)):
    x = jax.lax.conv_general_dilated(convdt(x), convdt(w), stride, padding,
          dimension_numbers=('NCHW', 'OIHW', 'NCHW')).astype(jnp.float32)
    return x + b.reshape(1, -1, 1, 1)

def max_pool2d(x, size=2, stride=2):
    return jax.lax.reduce_window(x, -jnp.inf, jax.lax.max,
             (1, 1, size, size), (1, 1, stride, stride), 'SAME')

def conv_bn(x, w, gamma, beta, stride=(1,1), padding='SAME'):
    x = jax.lax.conv_general_dilated(convdt(x), convdt(w), stride, padding,
          dimension_numbers=('NCHW', 'OIHW', 'NCHW')).astype(jnp.float32)
    # Batch normalization: mean/var over (N, H, W) per channel,
    # matching LeanMlir.MlirCodegen.emitConvBn's 2-step reduction
    # across dims [2,3] then [0] (divisor b*oH*oW).
    mean = jnp.mean(x, axis=(0, 2, 3), keepdims=True)
    var = jnp.var(x, axis=(0, 2, 3), keepdims=True)
    x = (x - mean) / jnp.sqrt(var + 1e-5)
    return x * gamma.reshape(1, -1, 1, 1) + beta.reshape(1, -1, 1, 1)

def basic_block(params, x, idx):
    out = conv_bn(x, params[idx][0], params[idx][1], params[idx][2])
    out = jax.nn.relu(out)
    out = conv_bn(out, params[idx+1][0], params[idx+1][1], params[idx+1][2])
    return jax.nn.relu(out + x)

def basic_block_down(params, x, idx, stride):
    out = conv_bn(x, params[idx][0], params[idx][1], params[idx][2], stride=(stride,stride))
    out = jax.nn.relu(out)
    out = conv_bn(out, params[idx+1][0], params[idx+1][1], params[idx+1][2])
    shortcut = conv_bn(x, params[idx+2][0], params[idx+2][1], params[idx+2][2], stride=(stride,stride))
    return jax.nn.relu(out + shortcut)

def bottleneck_block(params, x, idx, drop_key=None, keep_prob=1.0):
    out = conv_bn(x, params[idx][0], params[idx][1], params[idx][2])
    out = jax.nn.relu(out)
    out = conv_bn(out, params[idx+1][0], params[idx+1][1], params[idx+1][2])
    out = jax.nn.relu(out)
    out = conv_bn(out, params[idx+2][0], params[idx+2][1], params[idx+2][2])
    if drop_key is not None and keep_prob < 1.0:
        keep = jax.random.bernoulli(drop_key, keep_prob).astype(out.dtype)
        out = out * keep / keep_prob
    return jax.nn.relu(out + x)

def bottleneck_block_down(params, x, idx, stride, drop_key=None, keep_prob=1.0):
    out = conv_bn(x, params[idx][0], params[idx][1], params[idx][2])
    out = jax.nn.relu(out)
    out = conv_bn(out, params[idx+1][0], params[idx+1][1], params[idx+1][2], stride=(stride,stride))
    out = jax.nn.relu(out)
    out = conv_bn(out, params[idx+2][0], params[idx+2][1], params[idx+2][2])
    shortcut = conv_bn(x, params[idx+3][0], params[idx+3][1], params[idx+3][2], stride=(stride,stride))
    if drop_key is not None and keep_prob < 1.0:
        keep = jax.random.bernoulli(drop_key, keep_prob).astype(out.dtype)
        out = out * keep / keep_prob
    return jax.nn.relu(out + shortcut)

def global_avg_pool(x):
    return jnp.mean(x, axis=(2, 3))

# ═══════════════════════════════════════════════════════════════════════
#  Multi-GPU data parallelism
# ═══════════════════════════════════════════════════════════════════════

devices = jax.devices()
n_devices = len(devices)
mesh = Mesh(np.array(devices), axis_names=('batch',))
data_sharding = NamedSharding(mesh, P('batch'))
replicated_sharding = NamedSharding(mesh, P())

