def init_params_from_file(path):
    buf = np.frombuffer(open(path, 'rb').read(), dtype=np.float32)
    idx = 0
    params = []
    # convBn 3→64, 7×7 (W, γ, β)
    W = jnp.array(buf[idx:idx+9408].reshape(64, 3, 7, 7)); idx += 9408
    gamma = jnp.array(buf[idx:idx+64]); idx += 64
    beta = jnp.array(buf[idx:idx+64]); idx += 64
    params.append((W, gamma, beta))
    # bneck[0] 1x1 reduce 64→64 (W, γ, β)
    W = jnp.array(buf[idx:idx+4096].reshape(64, 64, 1, 1)); idx += 4096
    gamma = jnp.array(buf[idx:idx+64]); idx += 64
    beta = jnp.array(buf[idx:idx+64]); idx += 64
    params.append((W, gamma, beta))
    # bneck[0] 3x3 mid 64→64 (W, γ, β)
    W = jnp.array(buf[idx:idx+36864].reshape(64, 64, 3, 3)); idx += 36864
    gamma = jnp.array(buf[idx:idx+64]); idx += 64
    beta = jnp.array(buf[idx:idx+64]); idx += 64
    params.append((W, gamma, beta))
    # bneck[0] 1x1 expand 64→256 (W, γ, β)
    W = jnp.array(buf[idx:idx+16384].reshape(256, 64, 1, 1)); idx += 16384
    gamma = jnp.array(buf[idx:idx+256]); idx += 256
    beta = jnp.array(buf[idx:idx+256]); idx += 256
    params.append((W, gamma, beta))
    # bneck[0] proj 64→256 (W, γ, β)
    W = jnp.array(buf[idx:idx+16384].reshape(256, 64, 1, 1)); idx += 16384
    gamma = jnp.array(buf[idx:idx+256]); idx += 256
