def params_to_file(params, path):
    """Mirror of init_params_from_file. Walks the JAX `params`
    list in spec order and serializes each tensor as float32 bytes
    in the same on-disk byte layout the phase-3 Lean trainer uses.
    Drop the resulting .bin into TrainConfig.bootstrapBackbone.
    """
    idx = 0
    f = open(path, 'wb')
    # convBn 3→64, 7×7 (W, γ, β)
    W, gamma, beta = params[idx]; idx += 1
    f.write(np.asarray(W).astype(np.float32).flatten().tobytes())
    f.write(np.asarray(gamma).astype(np.float32).flatten().tobytes())
    f.write(np.asarray(beta).astype(np.float32).flatten().tobytes())
    # bneck[0] 1x1 reduce 64→64 (W, γ, β)
    W, gamma, beta = params[idx]; idx += 1
    f.write(np.asarray(W).astype(np.float32).flatten().tobytes())
    f.write(np.asarray(gamma).astype(np.float32).flatten().tobytes())
    f.write(np.asarray(beta).astype(np.float32).flatten().tobytes())
    # bneck[0] 3x3 mid 64→64 (W, γ, β)
    W, gamma, beta = params[idx]; idx += 1
    f.write(np.asarray(W).astype(np.float32).flatten().tobytes())
    f.write(np.asarray(gamma).astype(np.float32).flatten().tobytes())
    f.write(np.asarray(beta).astype(np.float32).flatten().tobytes())
    # bneck[0] 1x1 expand 64→256 (W, γ, β)
