def forward(params, x, drop_key=None):
    x = x.reshape(-1, 3, 224, 224)
    x = conv_bn(x, params[0][0], params[0][1], params[0][2], stride=(2,2), padding='SAME')
    x = jax.nn.relu(x)
    x = max_pool2d(x, 3, 2)
    x = bottleneck_block_down(params, x, 1, 1)
    x = bottleneck_block(params, x, 5)
    x = bottleneck_block(params, x, 8)
    x = bottleneck_block_down(params, x, 11, 2)
    x = bottleneck_block(params, x, 15)
    x = bottleneck_block(params, x, 18)
    x = bottleneck_block(params, x, 21)
    x = bottleneck_block_down(params, x, 24, 2)
    x = bottleneck_block(params, x, 28)
    x = bottleneck_block(params, x, 31)
    x = bottleneck_block(params, x, 34)
    x = bottleneck_block(params, x, 37)
    x = bottleneck_block(params, x, 40)
    x = bottleneck_block_down(params, x, 43, 2)
    x = bottleneck_block(params, x, 47)
    x = bottleneck_block(params, x, 50)
    x = global_avg_pool(x)
    x = mm(x, params[53][0].T) + params[53][1]
    return x

def loss_fn(params, x, y, drop_key=None):
    logits = forward(params, x, drop_key)
    log_probs = jax.nn.log_softmax(logits, axis=-1)
    # y is int32 [B] (hard labels) or float [B,NC] (soft labels, mixup/cutmix).
    # y.ndim is static at trace time, so this branch is jit-safe.
    if y.ndim == 1:
        tgt = jax.nn.one_hot(y, 10)
    else:
        tgt = y
    return -jnp.mean(jnp.sum(log_probs * tgt, axis=-1))

def augment_batch(x, rng):
    """Random crop (numpy, CPU): pad 224→252, crop back to 224x224."""
    x = x.reshape(-1, 3, 224, 224)
    x = np.pad(x, ((0,0), (0,0), (14,14), (14,14)))
    top = rng.randint(0, 29)
    left = rng.randint(0, 29)
    x = x[:, :, top:top+224, left:left+224]
    return x.reshape(x.shape[0], -1)

# ═══════════════════════════════════════════════════════════════════════
#  Training  (Adam + cosine LR)
# ═══════════════════════════════════════════════════════════════════════

LR = 0.001000
WD = 0.000100

@jit
def train_step(params, opt_state, x, y, lr, drop_key=None):
    loss, grads = value_and_grad(loss_fn)(params, x, y, drop_key)
    m, v, t = opt_state
    t = t + 1
    m = jax.tree.map(lambda mi, g: 0.9 * mi + 0.1 * g, m, grads)
    v = jax.tree.map(lambda vi, g: 0.999 * vi + 0.001 * g * g, v, grads)
    mc = jax.tree.map(lambda mi: mi / (1 - 0.9 ** t), m)
    vc = jax.tree.map(lambda vi: vi / (1 - 0.999 ** t), v)
    params = jax.tree.map(lambda p, mi, vi: p - lr * (mi / (jnp.sqrt(vi) + 1e-8) + WD * p), params, mc, vc)
    return params, (m, v, t), loss

@jit
def eval_batch(params, x, y):
    logits = forward(params, x)
    preds = jnp.argmax(logits, axis=-1)
    log_probs = jax.nn.log_softmax(logits, axis=-1)
    loss = -jnp.mean(jnp.sum(log_probs * jax.nn.one_hot(y, 10), axis=-1))
    correct1 = jnp.sum(preds == y)
    # top-5: jax.lax.top_k's indices are broken on ROCm/gfx1100 (garbage on
    # device, HIP error to host), so rank the true class instead — top-5 is
    # correct iff fewer than 5 classes have a strictly-greater logit.
    true_logit = jnp.take_along_axis(logits, y[:, None], axis=1)
    correct5 = jnp.sum(jnp.sum(logits > true_logit, axis=1) < 5)
    return correct1, correct5, loss

def evaluate(params, images, labels, batch_size=512):
    batch_size = (batch_size // n_devices) * n_devices or n_devices
    correct1 = 0
    correct5 = 0
    total_loss = 0.0
    n_batches = 0
    for i in range(0, len(images) - batch_size + 1, batch_size):
        c1, c5, l = eval_batch(params,
            jax.device_put(images[i:i+batch_size], data_sharding),
            jax.device_put(labels[i:i+batch_size], data_sharding))
        correct1 += int(c1)
        correct5 += int(c5)
        total_loss += float(l)
        n_batches += 1
    evaluated = n_batches * batch_size
    return correct1, correct5, evaluated, total_loss / max(n_batches, 1)

