if __name__ == "__main__":
    print("ResNet-50 · Lean 4 → JAX")
    print("  " + "Conv(3→64,7x7/2)+BN → Pool(3x3) → BN3(64→256,s1) → BN4(256→512,s2) → BN6(512→1024,s2) → BN3(1024→2048,s2) → GAP → 2048→10")
    print()

    data_dir = "data/imagenette"
    print("Loading Imagenette …")
    train_images, train_labels = load_imagenette(os.path.join(data_dir, "train.bin"))
    test_images, test_labels = load_imagenette(os.path.join(data_dir, "val.bin"))
    print("  " + str(len(train_images)) + " train, " + str(len(test_images)) + " val, 224x224x3")

    BATCH_SIZE = (192 // n_devices) * n_devices or n_devices
    EPOCHS = 80
    print("lr=0.001000  batch_size=" + str(BATCH_SIZE) + " (" + str(n_devices) + " devices x " + str(BATCH_SIZE // n_devices) + ")  epochs=" + str(EPOCHS) + "  params=23528522")
    print("backend=" + str(jax.default_backend()) + "  devices=" + str(jax.devices()))
    print("Starting training...")

    _init_load = os.environ.get('LEAN_MLIR_INIT_LOAD')
    if _init_load:
        print(f'Loading phase-3 init from {_init_load}')
        params = init_params_from_file(_init_load)
    else:
        params = init_params(random.PRNGKey(314159))
    params = jax.device_put(params, replicated_sharding)
    rng = np.random.RandomState(42)
    opt_m = jax.tree.map(jnp.zeros_like, params)
    opt_v = jax.tree.map(jnp.zeros_like, params)
    opt_state = (opt_m, opt_v, jnp.float32(0))

    # Data stays on CPU; batches transferred to GPU on the fly

    # Trace emission (opt-in via LEAN_MLIR_TRACE_OUT env var). Matches
    # the phase-3 format so cross-phase diffs work with tests/diff_traces.py.
    _trace_path = os.environ.get('LEAN_MLIR_TRACE_OUT')
    _trace_f = open(_trace_path, 'w') if _trace_path else None
    if _trace_f:
        _hdr = {
            'kind': 'header', 'phase': 'phase2',
            'netspec_name': "ResNet-50",
            'config': {
                'lr': 0.001000,
                'batch_size': 192,
                'epochs': 80,
                'use_adam': True,
                'weight_decay': 0.000100,
                'cosine': True,
                'warmup_epochs': 3,
                'augment': True,
                'label_smoothing': 0.000000,
                'seed': 314159,
            },
            'total_params': 23528522,
            'dataset': 'imagenette',
            'emitter_version': '1',
        }
        _trace_f.write(json.dumps(_hdr) + '\n')
    _global_step = 0
    t0 = time.time()
    for epoch in range(EPOCHS):
        # Cosine LR schedule with warmup
        if epoch < 3:
            lr = jnp.float32(LR * (epoch + 1) / 3)
        else:
            lr = jnp.float32(LR * 0.5 * (1 + np.cos(np.pi * (epoch - 3) / (EPOCHS - 3))))
        if os.environ.get('LEAN_MLIR_NO_SHUFFLE'):
            shuf_images = train_images
            shuf_labels = train_labels
        else:
            perm = rng.permutation(len(train_images))
            shuf_images = train_images[perm]
            shuf_labels = train_labels[perm]
        # Random horizontal flip (data augmentation)
        flip = rng.random(len(shuf_images)) > 0.5
        imgs4d = shuf_images.reshape(-1, 3, 224, 224)
        imgs4d[flip] = imgs4d[flip, :, :, ::-1]
        shuf_images = imgs4d.reshape(len(shuf_images), -1)
        epoch_loss = 0.0
        n_batches = 0
        for i in range(0, len(train_images) - BATCH_SIZE + 1, BATCH_SIZE):
            batch = augment_batch(shuf_images[i:i+BATCH_SIZE].copy(), rng)
            x = jax.device_put(batch, data_sharding)
            y = jax.device_put(shuf_labels[i:i+BATCH_SIZE], data_sharding)
            params, opt_state, loss = train_step(params, opt_state, x, y, lr)
            epoch_loss += float(loss)
            n_batches += 1
            _global_step += 1
            if _trace_f:
                _trace_f.write(json.dumps({
                    'kind': 'step', 'step': _global_step, 'epoch': epoch,
                    'loss': float(loss), 'lr': float(lr),
                }) + '\n')

        correct1, correct5, total, test_loss = evaluate(params, test_images, test_labels)
        acc1 = correct1 / total
        acc5 = correct5 / total
        elapsed = time.time() - t0
        print("[Epoch " + str(epoch+1) + "] lr=" + str(round(float(lr), 6)) +
              " top1: " + str(correct1) + "/" + str(total) +
              " (" + str(round(acc1, 4)) + ")" +
              " top5: " + str(round(acc5, 4)) +
              " Loss: " + str(round(test_loss, 4)) +
              "  [" + str(round(elapsed, 1)) + "s]")

    print("")
    print("Done. Total time: " + str(round(time.time() - t0, 1)) + "s")
    if _trace_f: _trace_f.close()
